/**
 * User notification preferences model.
 *
 * Controls how and when a user receives notifications across
 * multiple channels: email, SMS, and webhook.
 *
 * Each channel has independent enabled/subscribedCategories settings.
 * Email additionally supports delivery frequency (digest batching).
 */

import type { NotificationType } from './notification.js';

/**
 * How often email notifications are delivered.
 * - 'immediate': sent as events occur
 * - 'daily-digest': batched into a daily summary
 * - 'weekly-digest': batched into a weekly summary
 */
export type EmailFrequency = 'immediate' | 'daily-digest' | 'weekly-digest';

/**
 * Email-specific notification preferences.
 */
export interface EmailPreferences {
  /** Whether email notifications are enabled at all. */
  enabled: boolean;
  /** Delivery frequency. */
  frequency: EmailFrequency;
  /** Notification types the user wants to receive via email. */
  subscribedCategories: NotificationType[];
}

/**
 * SMS-specific notification preferences.
 */
export interface SmsPreferences {
  /** Whether SMS notifications are enabled at all. */
  enabled: boolean;
  /** Notification types the user wants to receive via SMS. */
  subscribedCategories: NotificationType[];
}

/**
 * Webhook-specific notification preferences.
 */
export interface WebhookPreferences {
  /** Whether webhook notifications are enabled at all. */
  enabled: boolean;
  /** Notification types the user wants to receive via webhook. */
  subscribedCategories: NotificationType[];
}

/**
 * Per-user notification preferences.
 */
export interface UserPreferences {
  userId: string;
  email: EmailPreferences;
  sms: SmsPreferences;
  webhook: WebhookPreferences;
  updatedAt: Date;
}

/**
 * Input for updating a user's email preferences.
 * Only provided fields are changed; others keep their current values.
 */
export interface UpdateEmailPreferencesInput {
  enabled?: boolean;
  frequency?: EmailFrequency;
  subscribedCategories?: NotificationType[];
}

/**
 * Input for updating a user's SMS preferences.
 * Only provided fields are changed; others keep their current values.
 */
export interface UpdateSmsPreferencesInput {
  enabled?: boolean;
  subscribedCategories?: NotificationType[];
}

/**
 * Input for updating a user's webhook preferences.
 * Only provided fields are changed; others keep their current values.
 */
export interface UpdateWebhookPreferencesInput {
  enabled?: boolean;
  subscribedCategories?: NotificationType[];
}

/**
 * All notification types — used as the default subscription set.
 */
export const ALL_NOTIFICATION_TYPES: NotificationType[] = [
  'order:confirmation',
  'order:status-update',
  'user:welcome',
  'user:profile-updated',
];

/**
 * Returns default preferences for a new user (all notifications enabled on all channels).
 */
export function createDefaultPreferences(userId: string): UserPreferences {
  return {
    userId,
    email: {
      enabled: true,
      frequency: 'immediate',
      subscribedCategories: [...ALL_NOTIFICATION_TYPES],
    },
    sms: {
      enabled: true,
      subscribedCategories: [...ALL_NOTIFICATION_TYPES],
    },
    webhook: {
      enabled: true,
      subscribedCategories: [...ALL_NOTIFICATION_TYPES],
    },
    updatedAt: new Date(),
  };
}

/**
 * Preferences service — manages per-user notification preferences.
 *
 * Stores preferences in memory. Users who have never set preferences
 * get defaults (all notifications enabled on all channels).
 *
 * Used by NotificationService to check whether a notification should
 * be sent to a given user on a given channel.
 */

import type { NotificationChannel, NotificationType } from '../models/notification.js';
import type {
  UserPreferences,
  UpdateEmailPreferencesInput,
  UpdateSmsPreferencesInput,
  UpdateWebhookPreferencesInput,
} from '../models/user-preferences.js';
import { createDefaultPreferences } from '../models/user-preferences.js';
import { Logger } from '../utils/logger.js';

export class PreferencesService {
  private logger = new Logger('PreferencesService');
  private preferences: Map<string, UserPreferences> = new Map();

  /**
   * Get preferences for a user. Returns defaults if none have been set.
   */
  getPreferences(userId: string): UserPreferences {
    const existing = this.preferences.get(userId);
    if (existing) {
      return {
        ...existing,
        email: { ...existing.email, subscribedCategories: [...existing.email.subscribedCategories] },
        sms: { ...existing.sms, subscribedCategories: [...existing.sms.subscribedCategories] },
        webhook: { ...existing.webhook, subscribedCategories: [...existing.webhook.subscribedCategories] },
      };
    }
    return createDefaultPreferences(userId);
  }

  /**
   * Update a user's email notification preferences.
   * Only provided fields are changed; others keep their current values.
   */
  updateEmailPreferences(userId: string, input: UpdateEmailPreferencesInput): UserPreferences {
    const current = this.getPreferences(userId);

    const updated: UserPreferences = {
      ...current,
      userId,
      email: {
        enabled: input.enabled ?? current.email.enabled,
        frequency: input.frequency ?? current.email.frequency,
        subscribedCategories: input.subscribedCategories ?? [...current.email.subscribedCategories],
      },
      updatedAt: new Date(),
    };

    this.preferences.set(userId, updated);
    this.logger.info(`Updated email preferences for user ${userId}`);
    return this.getPreferences(userId);
  }

  /**
   * Update a user's SMS notification preferences.
   * Only provided fields are changed; others keep their current values.
   */
  updateSmsPreferences(userId: string, input: UpdateSmsPreferencesInput): UserPreferences {
    const current = this.getPreferences(userId);

    const updated: UserPreferences = {
      ...current,
      userId,
      sms: {
        enabled: input.enabled ?? current.sms.enabled,
        subscribedCategories: input.subscribedCategories ?? [...current.sms.subscribedCategories],
      },
      updatedAt: new Date(),
    };

    this.preferences.set(userId, updated);
    this.logger.info(`Updated SMS preferences for user ${userId}`);
    return this.getPreferences(userId);
  }

  /**
   * Update a user's webhook notification preferences.
   * Only provided fields are changed; others keep their current values.
   */
  updateWebhookPreferences(userId: string, input: UpdateWebhookPreferencesInput): UserPreferences {
    const current = this.getPreferences(userId);

    const updated: UserPreferences = {
      ...current,
      userId,
      webhook: {
        enabled: input.enabled ?? current.webhook.enabled,
        subscribedCategories: input.subscribedCategories ?? [...current.webhook.subscribedCategories],
      },
      updatedAt: new Date(),
    };

    this.preferences.set(userId, updated);
    this.logger.info(`Updated webhook preferences for user ${userId}`);
    return this.getPreferences(userId);
  }

  /**
   * Check whether a notification should be sent to a user via email.
   */
  shouldSendEmail(userId: string, notificationType: NotificationType): boolean {
    const prefs = this.getPreferences(userId);
    if (!prefs.email.enabled) {
      this.logger.info(`Email disabled for user ${userId}, skipping ${notificationType}`);
      return false;
    }
    if (!prefs.email.subscribedCategories.includes(notificationType)) {
      this.logger.info(`User ${userId} not subscribed to ${notificationType} on email, skipping`);
      return false;
    }
    return true;
  }

  /**
   * Check whether a notification should be sent to a user via SMS.
   */
  shouldSendSms(userId: string, notificationType: NotificationType): boolean {
    const prefs = this.getPreferences(userId);
    if (!prefs.sms.enabled) {
      this.logger.info(`SMS disabled for user ${userId}, skipping ${notificationType}`);
      return false;
    }
    if (!prefs.sms.subscribedCategories.includes(notificationType)) {
      this.logger.info(`User ${userId} not subscribed to ${notificationType} on SMS, skipping`);
      return false;
    }
    return true;
  }

  /**
   * Check whether a notification should be sent to a user via webhook.
   */
  shouldSendWebhook(userId: string, notificationType: NotificationType): boolean {
    const prefs = this.getPreferences(userId);
    if (!prefs.webhook.enabled) {
      this.logger.info(`Webhook disabled for user ${userId}, skipping ${notificationType}`);
      return false;
    }
    if (!prefs.webhook.subscribedCategories.includes(notificationType)) {
      this.logger.info(`User ${userId} not subscribed to ${notificationType} on webhook, skipping`);
      return false;
    }
    return true;
  }

  /**
   * Check whether a notification should be sent on a given channel.
   * Dispatches to the appropriate per-channel check.
   * Returns true for channels without preference support (e.g. in-app).
   */
  shouldSend(userId: string, channel: NotificationChannel, notificationType: NotificationType): boolean {
    switch (channel) {
      case 'email':
        return this.shouldSendEmail(userId, notificationType);
      case 'sms':
        return this.shouldSendSms(userId, notificationType);
      case 'webhook':
        return this.shouldSendWebhook(userId, notificationType);
      default:
        return true;
    }
  }

  /**
   * Get the email frequency setting for a user.
   */
  getEmailFrequency(userId: string): UserPreferences['email']['frequency'] {
    return this.getPreferences(userId).email.frequency;
  }

  /**
   * Delete preferences for a user (reverts to defaults).
   */
  deletePreferences(userId: string): boolean {
    const existed = this.preferences.has(userId);
    this.preferences.delete(userId);
    if (existed) {
      this.logger.info(`Deleted preferences for user ${userId}`);
    }
    return existed;
  }

  /**
   * Clear all stored preferences. Useful for testing.
   */
  clearAll(): void {
    this.preferences.clear();
  }
}

